function candidate(settings) {
  var formatters = {
    RFC1738: function (value) {
      return String(value).replace(/%20/g, '+');
    },
    RFC3986: function (value) {
      return String(value);
    }
  };

  function defaultEncoder(value) {
    return encodeURIComponent(String(value));
  }

  function defaultDateSerializer(value) {
    return value instanceof Date ? value.toISOString() : value;
  }

  var sharedDefault = candidate.defaultConfig || (candidate.defaultConfig = {
    encoding: defaultEncoder,
    textEncoding: 'utf-8',
    format: 'RFC3986',
    formatter: formatters.RFC3986,
    filter: null,
    allowDots: false,
    encodeValuesOnly: false,
    skipNulls: false,
    strictNullHandling: false,
    delimiter: '&',
    sort: null,
    serializeDate: defaultDateSerializer
  });

  if (settings == null) {
    return sharedDefault;
  }

  var encodingCallback = settings.encoding || settings.encoder;
  if (encodingCallback != null && typeof encodingCallback !== 'function') {
    throw new TypeError('Encoder must be a function.');
  }

  var requestedEncoding = settings.textEncoding || settings.charset;
  if (requestedEncoding == null) {
    requestedEncoding = sharedDefault.textEncoding;
  } else {
    requestedEncoding = String(requestedEncoding).toLowerCase();
    if (requestedEncoding !== 'utf-8' && requestedEncoding !== 'iso-8859-1') {
      throw new TypeError('The text encoding must be utf-8 or iso-8859-1.');
    }
  }

  var requestedFormat = settings.format == null ? sharedDefault.format : settings.format;
  if (!Object.prototype.hasOwnProperty.call(formatters, requestedFormat)) {
    throw new TypeError('Unknown format option provided.');
  }

  return {
    encoding: encodingCallback || sharedDefault.encoding,
    textEncoding: requestedEncoding,
    format: requestedFormat,
    formatter: formatters[requestedFormat],
    filter: typeof settings.filter === 'function' || Array.isArray(settings.filter) ? settings.filter : sharedDefault.filter,
    allowDots: typeof settings.allowDots === 'boolean' ? settings.allowDots : !!settings.allowDots,
    encodeValuesOnly: typeof settings.encodeValuesOnly === 'boolean' ? settings.encodeValuesOnly : sharedDefault.encodeValuesOnly,
    skipNulls: typeof settings.skipNulls === 'boolean' ? settings.skipNulls : sharedDefault.skipNulls,
    strictNullHandling: typeof settings.strictNullHandling === 'boolean' ? settings.strictNullHandling : sharedDefault.strictNullHandling,
    delimiter: typeof settings.delimiter === 'string' ? settings.delimiter : sharedDefault.delimiter,
    sort: typeof settings.sort === 'function' ? settings.sort : null,
    serializeDate: typeof settings.serializeDate === 'function' ? settings.serializeDate : sharedDefault.serializeDate
  };
}
